def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    log_factor = np.log1p(item)
    sqrt_item = np.sqrt(item)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.05:
            base = np.exp(-ratio * 12)
            for a in range(1, 15):
                weight = (a ** 3.1) * (np.sin(a) + 1.5)
                modifier = 1.1 if a % 4 == 0 else 0.85
                increment = base * weight * modifier
                score += increment
            if (capacity + item) % 2 == 0:
                score *= 0.75
            if score > 12:
                score = np.cbrt(score) * 3
        elif 0.05 <= ratio < 0.25:
            prod = 1.0
            for n in range(1, int(capacity) + 5):
                addend = (ratio + n / (n + 2)) ** 1.1
                prod *= addend
                if prod > 2e7:
                    prod = np.log1p(prod) * 2
                    break
            mod_val = int(prod) % 500
            score += np.sqrt(ratio * mod_val + 2.2)
            if int(capacity) % 5 == 0 and int(item * 6) % 7 == 0:
                score += 6.7
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 9):
                extra_sum += ((ratio * x ** 3) % 1) * (x ** 1.5)
            score += extra_sum / 7
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 10):
                exp_term = (ratio ** (m + 3)) * (m ** 3.2) / ((m + 3) ** 1.1)
                score += exp_term
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -8:
                score = abs(score) * 0.2 + 3
            if int(capacity) % 8 == 0:
                score *= 1.35
            if score > 25:
                score /= 4
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0
            diff = ratio - 0.55
            for p in range(1, 12):
                term = (diff ** p) * (p ** 1.9) * np.cos(p)
                penalty_base += term
                if penalty_base > 60:
                    penalty_base = np.sqrt(penalty_base)
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 7) % 9 == 0) and (int(item * 10) % 13 == 0):
                score -= 8
            if score < 0:
                score = -score * 1.6 + 7
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 15):
                term = ((diff) ** q) * (q ** 3.1) / (q + 0.5) * np.sin(q)
                penalty_ext += term
            score = penalty_ext * 18
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 5 == 0):
                score -= 10
            for z in range(1, 9):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1400:
                score = 1400
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.9) * np.cos(r + diff)
                if term > 15000:
                    term = np.cbrt(term)
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 17) % 5 == 0) and (int(item * 19) % 7 == 0):
                score -= 12
            for w in range(3, 10):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 3000:
                score = 3000
        if capacity > 500:
            score /= (np.log1p(capacity) + 1.5)
            score *= np.tanh(capacity / 800)
        elif capacity < 7:
            score *= 2.8
            for adj in range(1, 4):
                score += ((item + capacity) % (adj + 1)) * adj
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q = np.percentile(finite_priorities, [20, 40, 60, 80])
        peaks = np.sum(finite_priorities > q[3])
        median_val = q[2]
        fill_value = np.max(finite_priorities) * (20 + peaks) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    median_finite = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_finite
    return priorities
